import { useEffect, useState } from "react";

import axios from "axios";

export default function LabourDashboard() {

  const user =
    JSON.parse(localStorage.getItem("user"));

  const [requests, setRequests] =
    useState([]);

  const [price, setPrice] =
    useState({});

  // FETCH REQUESTS
  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {

    try {

      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);

    }
  };

  // ACCEPT REQUEST
  const acceptRequest = async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price[id] || 0,
          action: "accepted"
        }
      );

      alert("Request Accepted");

      fetchRequests();

    } catch (err) {

      console.log(err);

    }
  };

  // REJECT REQUEST
  const rejectRequest = async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: 0,
          action: "rejected"
        }
      );

      alert("Request Rejected");

      fetchRequests();

    } catch (err) {

      console.log(err);

    }
  };

  return (

    <div style={styles.page}>

      <h2 style={styles.title}>
        Labour Dashboard
      </h2>

      {/* REQUESTS */}

      {requests.map((req) => (

        <div
          key={req._id}
          style={styles.card}
        >

          <h3 style={styles.work}>
            {req.workType}
          </h3>

          <p>
            <b>Customer:</b>
            {" "}
            {req.customerName}
          </p>

          <p>
            <b>Location:</b>
            {" "}
            {req.location}
          </p>

          <p>
            <b>Date:</b>
            {" "}
            {req.date}
          </p>

          <p>
            <b>Status:</b>
            {" "}
            <span
              style={{
                color:
                  req.status === "accepted"
                    ? "green"
                    : req.status === "rejected"
                    ? "red"
                    : "#f59e0b"
              }}
            >
              {req.status}
            </span>
          </p>

          {/* PAYMENT */}

          {req.status === "Pending" && (

            <input
              style={styles.input}
              placeholder="Enter Payment"
              onChange={(e) =>
                setPrice({
                  ...price,
                  [req._id]:
                    e.target.value
                })
              }
            />

          )}

          {/* BUTTONS */}

          {req.status === "Pending" && (

            <div style={styles.row}>

              <button
                style={styles.acceptBtn}
                onClick={() =>
                  acceptRequest(
                    req._id
                  )
                }
              >
                Accept
              </button>

              <button
                style={styles.rejectBtn}
                onClick={() =>
                  rejectRequest(
                    req._id
                  )
                }
              >
                Reject
              </button>

            </div>

          )}

          {/* PRICE */}

          {req.labourPrice > 0 && (

            <p>
              <b>Payment:</b>
              {" "}
              ₹{req.labourPrice}
            </p>

          )}

          {/* CUSTOMER FINAL STATUS */}

          <p>
            <b>Customer Decision:</b>
            {" "}
            {req.customerDecision}
          </p>

          {/* RATING */}

          {req.feedback && (

            <div style={styles.feedback}>

              <p>
                <b>Rating:</b>
                {" "}
                ⭐ {req.feedback.rating}/5
              </p>

              <p>
                <b>Review:</b>
                {" "}
                {req.feedback.comment}
              </p>

            </div>

          )}

        </div>

      ))}

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    padding: "30px",
    fontFamily: "Arial"
  },

  title: {
    textAlign: "center",
    marginBottom: "25px",
    color: "#111827"
  },

  card: {
    background: "white",
    padding: "20px",
    borderRadius: "16px",
    marginBottom: "20px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  work: {
    color: "#2563eb",
    marginBottom: "10px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    marginTop: "12px",
    marginBottom: "12px",
    outline: "none",
    boxSizing: "border-box"
  },

  row: {
    display: "flex",
    gap: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "12px",
    background: "#16a34a",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "12px",
    background: "#dc2626",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  },

  feedback: {
    marginTop: "15px",
    background: "#f9fafb",
    padding: "12px",
    borderRadius: "10px"
  }

};
